// Admin page template - base64 encoded
// Generated from admin.html

window.ADMIN_PAGE_BASE64 = "";

function renderAdminPanel() {
  if (typeof requireAdmin !== 'function') { window.location.href = 'index.html'; return; }
  requireAdmin().then(function(user) {
    if (!user) return;
    var html = atob(window.ADMIN_PAGE_BASE64);
    document.open();
    document.write(html);
    document.close();
  });
}
